        "prop": "onChange",
        "type": "function",
        "default": "—",
        "required": "No",
        "desc": "Selection change handler. Single-select payload: { value: string | null, previousValue: string | null }. Multi-select payload: { values: string[], changedValue: string, selected: boolean }. Suppressed when group is disabled or loading."
